import{_ as t,o as a,c as i,ag as s}from"./chunks/framework.DXGyWiRo.js";const f=JSON.parse('{"title":"LinkedQL — The Database Primitive For Applications And Agents","description":"","frontmatter":{},"headers":[],"relativePath":"overview.md","filePath":"overview.md"}'),r={name:"overview.md"};function n(l,e,o,d,h,c){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="linkedql-—-the-database-primitive-for-applications-and-agents" tabindex="-1">LinkedQL <br>— The Database Primitive For Applications And Agents <a class="header-anchor" href="#linkedql-—-the-database-primitive-for-applications-and-agents" aria-label="Permalink to &quot;LinkedQL &lt;br&gt;— The Database Primitive For Applications And Agents&quot;">​</a></h1><p><strong>Welcome to the docs.</strong> This page gives you the core thinking around LinkedQL and helps you map the system at a glance.</p><hr><h2 id="what-is-linkedql" tabindex="-1">What is LinkedQL? <a class="header-anchor" href="#what-is-linkedql" aria-label="Permalink to &quot;What is LinkedQL?&quot;">​</a></h2><p>LinkedQL is a portable query engine that runs in any JavaScript application and directly powers application state.</p><p>It extends SQL with a small set of composable capabilities for relationships, reactivity, and cross-runtime state — directly enabling real-time, local-first, and offline-first application architectures.</p><h3 id="what-it-replaces" tabindex="-1">What It Replaces <a class="header-anchor" href="#what-it-replaces" aria-label="Permalink to &quot;What It Replaces&quot;">​</a></h3><p>LinkedQL composes capabilities traditionally handled by separate systems — ORMs (e.g. Prisma), API/query layers (e.g. GraphQL), and sync engines (e.g. ElectricSQL) — directly into SQL.</p><p>This shifts applications from manual capability scaffolding to a unified, composable, SQL-based model for application logic and state.</p><h3 id="where-it-runs" tabindex="-1">Where It Runs <a class="header-anchor" href="#where-it-runs" aria-label="Permalink to &quot;Where It Runs&quot;">​</a></h3><p>LinkedQL is not tied to a single execution environment or architectural pattern.</p><p>It can be used as a query client over existing PostgreSQL and MySQL/MariaDB databases, embedded directly into JavaScript runtimes (browser, server, workers, edge), or used as a cross-runtime query layer – as architecture demands.</p><p>The same application-facing contract applies across all environments.</p><h2 id="why-linkedql" tabindex="-1">Why LinkedQL? <a class="header-anchor" href="#why-linkedql" aria-label="Permalink to &quot;Why LinkedQL?&quot;">​</a></h2><p>LinkedQL is the destination you arrive at when you solve the application data layer as one domain problem.</p><p>Most current efforts—from ORMs to API/query layers to sync systems—either solve only a slice of that problem or do so in ways that don’t compose.</p><p>Each sees the dots in isolation and tries to solve them individually.</p><p>The core insight behind LinkedQL is <em>how those dots connect together at the SQL level</em>.</p><hr><h2 id="your-map-to-the-docs" tabindex="-1">Your Map to the Docs <a class="header-anchor" href="#your-map-to-the-docs" aria-label="Permalink to &quot;Your Map to the Docs&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Area</th><th style="text-align:left;">What it covers</th><th style="text-align:left;">Go to...</th></tr></thead><tbody><tr><td style="text-align:left;">Core Guides</td><td style="text-align:left;">From basic setup to first queries, to more comprehensive guides</td><td style="text-align:left;"><a href="/guides">LinkedQL Guides</a></td></tr><tr><td style="text-align:left;">API</td><td style="text-align:left;">Core API contract — the interface and query model</td><td style="text-align:left;"><a href="/api">LinkedQL API</a></td></tr><tr><td style="text-align:left;">Language</td><td style="text-align:left;">The LinkedQL language surface (JSON Literals, DeepRefs, etc.)</td><td style="text-align:left;"><a href="/lang">Language Surface</a></td></tr><tr><td style="text-align:left;">Realtime</td><td style="text-align:left;">Live queries and subscription model</td><td style="text-align:left;"><a href="/realtime">Realtime Capabilities</a></td></tr><tr><td style="text-align:left;">FlashQL</td><td style="text-align:left;">LinkedQL&#39;s embeddable SQL engine for local execution, federation, and sync</td><td style="text-align:left;"><a href="/flashql">FlashQL</a></td></tr></tbody></table>',21)])])}const u=t(r,[["render",n]]);export{f as __pageData,u as default};
